import{_ as a,o as t,c as r,a0 as i}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"Import History & Change Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"imports/history-and-changes.md","filePath":"imports/history-and-changes.md"}'),s={name:"imports/history-and-changes.md"};function o(l,e,h,n,p,c){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="import-history-change-tracking" tabindex="-1">Import History &amp; Change Tracking <a class="header-anchor" href="#import-history-change-tracking" aria-label="Permalink to &quot;Import History &amp; Change Tracking&quot;">​</a></h1><p>The imports page is not just an upload screen. It is also the history view for what was processed, reviewed, applied, rolled back, or restored.</p><h2 id="what-import-history-shows" tabindex="-1">What import history shows <a class="header-anchor" href="#what-import-history-shows" aria-label="Permalink to &quot;What import history shows&quot;">​</a></h2><p>The history table shows items such as:</p><ul><li>file name</li><li>source</li><li>event</li><li>date</li><li>status</li><li>row count</li></ul><p>That makes it the quickest place to answer, &quot;Which import was this?&quot;</p><h2 id="review-page-history-details" tabindex="-1">Review page history details <a class="header-anchor" href="#review-page-history-details" aria-label="Permalink to &quot;Review page history details&quot;">​</a></h2><p>When you open an import review page, you can also inspect:</p><ul><li>the saved result rows</li><li>related record batches</li><li>raw processing data</li></ul><p>This is useful when you want both the business view and the evidence behind it.</p><h2 id="why-change-tracking-matters" tabindex="-1">Why change tracking matters <a class="header-anchor" href="#why-change-tracking-matters" aria-label="Permalink to &quot;Why change tracking matters&quot;">​</a></h2><p>Accepted rows leave a change trail that helps rollback work safely later.</p><p>That is especially important for:</p><ul><li>created players</li><li>overwritten results</li><li>field updates such as power</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./overview.html">How Screenshot Imports Work</a></li><li><a href="./delete-and-rollback.html">Delete an Import &amp; Roll Back Its Changes</a></li><li><a href="./restore-import.html">Restore a Deleted Import</a></li></ul>',16)])])}const u=a(s,[["render",o]]);export{m as __pageData,u as default};
